import { computed } from 'vue';
import { useCustomerStore } from '@/stores/customerStore';
import type { Table, MenuItem, CartItem, Order, KitchenTicket, ServiceRequest } from '@/types/customer';

export const useBusinessRules = () => {
  const store = useCustomerStore();

  const rules = {
    // ─── NV1 - Table Selection ───────────────────────────────────────────
    BR01: (passcode: string) => passcode.length === 6,
    BR02: () => store.selectedAreaId !== null,
    BR03: () => store.selectedTable !== null,
    BR04: (table: Table) => table.status === 'available',
    BR05: () => store.session === null, // Only 1 session/tablet at a time
    BR06: (table: Table) => !table.currentSessionId,
    BR07: (router: any) => router.push('/customer/menu'),
    BR08: (releaseCallback: () => void) => {
      // 60s timeout for selecting table state
      return setTimeout(releaseCallback, 60000);
    },

    // ─── NV2 - Menu ──────────────────────────────────────────────────────
    BR09: () => store.session !== null, // Must have active session to order
    BR10: () => store.menuData.length > 0,
    BR11: () => {
      // Preserve cart when switching categories
      // This is handled by storing cart in Pinia store state
      return true;
    },
    BR12: (item: MenuItem) => store.addToCart(item),
    BR13: (item: MenuItem) => {
      const existing = store.cart.find(i => i.menuItemId === item.id);
      if (existing) {
        store.updateCartItem(item.id, existing.quantity + 1);
      } else {
        store.addToCart(item);
      }
    },
    BR14: (quantity: number) => quantity > 0 && quantity <= 99,
    BR15: () => {
      // Auto-update cart total
      // Handled by Pinia store getters: cartTotal, cartItemCount, grandTotal
      return true;
    },
    BR16: (router: any) => router.push('/customer/cart'),
    BR17: () => store.menuData,

    // ─── NV4 - Cart & Order ──────────────────────────────────────────────
    BR18: () => store.cart.length === 0,
    BR19: (item: CartItem, qty: number) => {
      if (qty <= 0) {
        store.removeFromCart(item.menuItemId);
      } else if (qty <= 99) {
        store.updateCartItem(item.menuItemId, qty);
      }
    },
    BR20: (items: CartItem[]) => {
      items.forEach(item => store.removeFromCart(item.menuItemId));
    },
    BR21: () => {
      // Recalculate totals
      return {
        subtotal: store.cartTotal,
        serviceCharge: store.serviceCharge,
        vat: store.vat,
        grandTotal: store.grandTotal
      };
    },
    BR22: () => store.cart.length > 0,
    BR23: (order: Order): KitchenTicket[] => {
      // Classify by kitchen station (hot, meat, salad)
      const stations: Record<'hot' | 'meat' | 'salad', CartItem[]> = {
        hot: [],
        meat: [],
        salad: []
      };

      order.items.forEach(item => {
        // Simple logic to classify item names
        const nameLower = item.name.toLowerCase();
        if (nameLower.includes('wagyu') || nameLower.includes('thăn') || nameLower.includes('sườn') || nameLower.includes('heo') || nameLower.includes('ba chỉ')) {
          stations.meat.push(item);
        } else if (nameLower.includes('salad') || nameLower.includes('rau') || nameLower.includes('kem') || nameLower.includes('chè')) {
          stations.salad.push(item);
        } else {
          stations.hot.push(item); // Default to hot kitchen for soup, hotpot, drinks etc.
        }
      });

      const tickets: KitchenTicket[] = [];
      (Object.keys(stations) as Array<'hot' | 'meat' | 'salad'>).forEach(station => {
        if (stations[station].length > 0) {
          tickets.push({
            id: `ticket-${station}-${Date.now()}`,
            orderId: order.id,
            kitchenStation: station,
            items: stations[station],
            printedCount: 0,
            printedAt: new Date()
          });
        }
      });
      return tickets;
    },
    BR24: (station: 'hot' | 'meat' | 'salad', items: CartItem[]) => {
      return items.filter(item => {
        const nameLower = item.name.toLowerCase();
        if (station === 'meat') {
          return nameLower.includes('wagyu') || nameLower.includes('thăn') || nameLower.includes('sườn') || nameLower.includes('heo') || nameLower.includes('ba chỉ');
        } else if (station === 'salad') {
          return nameLower.includes('salad') || nameLower.includes('rau') || nameLower.includes('kem') || nameLower.includes('chè');
        } else {
          return !nameLower.includes('wagyu') && !nameLower.includes('thăn') && !nameLower.includes('sườn') && !nameLower.includes('heo') && !nameLower.includes('ba chỉ') && !nameLower.includes('salad') && !nameLower.includes('rau') && !nameLower.includes('kem') && !nameLower.includes('chè');
        }
      });
    },
    BR25: (ticket: KitchenTicket) => {
      // Validate ticket content
      return ticket.id && ticket.orderId && ticket.items.length > 0;
    },
    BR26: () => new Date(),
    BR27: (ticket: KitchenTicket, tableNumber: string) => {
      // Ticket formatting (mock helper)
      return `[TICKET BẾP] BÀN ${tableNumber} | Trạm: ${ticket.kitchenStation.toUpperCase()}`;
    },
    BR28: (ticket: KitchenTicket) => {
      ticket.printedCount++;
      ticket.printedAt = new Date();
    },

    // ─── NV5 - History & Payment ──────────────────────────────────────────
    BR29: (order: Order) => order.status === 'confirmed',
    BR30: (item: CartItem) => !!(item.name && item.price && item.quantity),
    BR31: (order: Order) => {
      const subtotal = order.items.reduce((sum, i) => sum + i.price * i.quantity, 0);
      const serviceCharge = Math.round(subtotal * 0.05); // 5% service charge
      const vat = Math.round((subtotal + serviceCharge) * 0.08); // 8% VAT
      const discount = order.discount || 0;
      return subtotal + serviceCharge + vat - discount;
    },
    BR32: () => store.requestInvoice(),
    BR33: () => store.requestPayment(),
    BR34: () => store.currentView = 'feedback',
    BR35: (rating: number) => rating >= 1 && rating <= 5,
    BR36: (criteria: string[]) => criteria.length >= 1,
    BR37: (comment: string) => true, // Optional comments
    BR38: (sessionId: string) => {
      // Check if feedback already submitted for session
      return store.feedback !== null && store.feedback.sessionId === sessionId;
    }
  };

  return rules;
};

import { ref } from 'vue'
import { supabase } from '@/lib/supabase'
import { useBranch, throwBranchGuard } from './useBranch'
import type { MenuCategory, MenuItem, Package as PackageRow } from '@/types/database'

export function useMenu() {
  const { activeBranchId } = useBranch()
  const loading = ref(false)
  const error = ref<string | null>(null)

  async function getCategories(branchOverride?: string): Promise<MenuCategory[]> {
    loading.value = true
    error.value = null
    const { data, error: err } = await supabase.rpc('customer_list_menu_categories', {
      p_branch_id: branchOverride ?? activeBranchId.value ?? throwBranchGuard(),
    })
    loading.value = false
    if (err) {
      error.value = err.message
      throw err
    }
    return (data ?? []) as MenuCategory[]
  }

  async function getItems(categoryId?: string, branchOverride?: string): Promise<MenuItem[]> {
    loading.value = true
    error.value = null
    const { data, error: err } = await supabase.rpc('customer_list_menu_items', {
      p_branch_id: branchOverride ?? activeBranchId.value ?? throwBranchGuard(),
      p_category_id: categoryId ?? null,
    })
    loading.value = false
    if (err) {
      error.value = err.message
      throw err
    }
    return (data ?? []) as MenuItem[]
  }

  async function getPackages(): Promise<PackageRow[]> {
    loading.value = true
    error.value = null
    const { data, error: err } = await supabase.rpc('hall_list_packages', {
      p_branch_id: activeBranchId.value ?? throwBranchGuard(),
    })
    loading.value = false
    if (err) {
      error.value = err.message
      throw err
    }
    return (data ?? []) as PackageRow[]
  }

  async function upsertItem(item: Partial<MenuItem>): Promise<MenuItem> {
    const payload = { ...item, branch_id: activeBranchId.value }
    const { data, error: err } = await supabase
      .from('menu_items')
      .upsert(payload)
      .select('*')
      .single<MenuItem>()
    if (err) throw err
    return data!
  }

  return { loading, error, getCategories, getItems, getPackages, upsertItem }
}

/**
 * Shared package + promo rule engine.
 *
 * Both the cashier (ReceptionOrderView.vue) and the customer menu
 * (CustomerMenu.vue) need to decide:
 *   1. Whether a given menu item is "included" in a buffet package
 *      (free when ordered inside the package), and
 *   2. Whether lunch-time / promo discounts apply.
 *
 * Before this module existed, each side carried its own copy of these
 * rules — and they diverged. The cashier used subcategory IDs
 * (`isEligibleMenu` via `parentCatId`), the customer matched on names
 * (`name.includes('1390')`). Same business intent, two implementations,
 * slow re-renders on both sides. This file is the single source of
 * truth.
 *
 * Spec source: docs/member_status/Ishii/02_07_2026.md (5 buffet SETs,
 * Kids Meal, Buffet Lẩu, Set 550JP, A la carte) + Ishii VAT 8% /
 * service 5% / lunch 50%.
 */

export interface PackageRuleItem {
  id: string
  name: string
  category_id: string
  /** Subcategory id from `menu_categories`. Pass `''` when unknown. */
  subCatId?: string
  /** Per-unit price; kept here so callers can zero it when in-pkg. */
  price: number
}

/**
 * Categories whose items are buffet-eligible in principle. Subcategory
 * ID filtering then decides which tier actually includes the item.
 */
const ELIGIBLE_PARENT_CATEGORIES = new Set([
  'thuc_an',         // Thức ăn
  'thuc_uong',       // Thức uống (no alcohol)
  'thuc_uong_co_con', // Thức uống có cồn
  'buffet',
])

/**
 * Subcategories that explicitly include WAGYU / premium beef. Used as
 * a normalised signal so callers can either pass `subCatId` (cashier
 * path) or fall back to id-includes checks (customer path).
 */
const WAGYU_HINTS = ['wagyu']
const PREMIUM_BEEF_HINTS = [
  'premium', 'sirloin', 'short_ribs', 'short-ribs',
  'tongue', 'beef_tongue', 'thăn ngoại', 'dẻ sườn', 'lưỡi',
]
const BEEF_HINTS = [
  'beef', 'wagyu', 'tongue', 'bò',
  'thăn', 'sirloin', 'sườn', 'lưỡi',
]
const ALCOHOL_HINTS = [
  'beer', 'whisky', 'shochu', 'nihonshuu', 'wine',
  'alcohol_set', 'rượu', 'soju', 'bia',
]
const DESSERT_HINTS = ['dessert']

/**
 * Subcategories allowed in the cheap buffet tiers (490 / 380). These
 * are the "safe" items that don't bleed into premium-beef territory
 * but still cover the full meal arc (rice, soup, noodles, drink…).
 */
const ALLOWED_LOW_TIER_SUBCATS = new Set([
  'pork', 'chicken',
  'soft_drink', 'tea', 'non_alcoholic',
  'appetizer', 'salad', 'rice', 'noodle', 'soup',
  'dessert', 'sauce',
  'sukiyaki', 'grill_alacarte', 'alacarte',
])

const KIDS_HINTS = ['kids', 'kid', 'egg', 'fries']
const LAU_HINTS = ['lẩu', 'lau', 'rau', 'nước', 'coca', 'bia', 'nấm']
const SET_550JP_HINTS = ['bento', 'sashimi', 'tempura', 'miso']
const DRINK_HINTS = ['uong', 'con']
const LUNCH_HINTS = ['lunch']

function lc(s: string): string {
  return (s ?? '').toLowerCase()
}

/**
 * Returns true iff this item is a surcharge that should NEVER be free
 * inside a package (per Ishii 02/07/2026: `khac-phi` items are always
 * charged). Apply for every package.
 */
export function isSurchargeItem(item: PackageRuleItem): boolean {
  if (item.category_id === 'khac' && (item.subCatId ?? '') === 'surcharge') {
    return true
  }
  // Defensive fallback: id / name containing "khac-phi" / "surcharge"
  // is rare but worth catching.
  const k = lc(item.id) + lc(item.name)
  return k.includes('khac-phi') || k.includes('surcharge')
}

function hasAny(haystack: string, needles: readonly string[]): boolean {
  return needles.some((n) => haystack.includes(n))
}

/**
 * Resolve the buffet tier that this item belongs to. `null` means the
 * item is not package-eligible at the current packageName.
 *
 *   - `1390`  — top tier, anything in ELIGIBLE_PARENT_CATEGORIES
 *   - `1150`  — everything in the 1390 tier EXCEPT wagyu
 *   - `680`   — 1150 tier EXCEPT wagyu + premium beef
 *   - `490` / `380` — only "safe" subcategories, no beef, no alcohol
 *   - `kids` — KIDS / egg / fries / dessert only
 *   - `lau`  — buffet lẩu (hotpot dishes + drinks + veggies)
 *   - `550jp`— Set 550JP (bento / sashimi / tempura / miso)
 *   - `drink`— SET DRINK-only packages
 *
 * The caller passes the currently-selected package name so we can
 * short-circuit when the package isn't recognised.
 */
export function getPackageTier(
  item: PackageRuleItem,
  packageName: string,
): string | null {
  if (!packageName) return null
  const name = lc(packageName)
  const sub = lc(item.subCatId ?? '')
  const id = lc(item.id)
  const itemName = lc(item.name)
  const parent = lc(item.category_id)

  // Surcharges are never included in any buffet.
  if (isSurchargeItem(item)) return null

  // A la carte menu is its own thing — never bundled.
  if (name.includes('a la carte')) return null

  // Kids meal package
  if (name.includes('kids')) {
    if (hasAny(id + itemName + sub, KIDS_HINTS)) return 'kids'
    if (hasAny(sub + parent, DESSERT_HINTS)) return 'kids'
    return null
  }

  // SET DRINK — only drinks + soup + veg sides that pair with a drink
  if (name.includes('drink')) {
    return parent.includes('uong') || sub.includes('uong') ||
           sub.includes('con') || parent.includes('con') ? 'drink' : null
  }

  // Buffet Lẩu (hotpot) — the soup base + raw ingredients + drinks
  if (name.includes('lẩu')) {
    return hasAny(itemName + sub + id, LAU_HINTS) ? 'lau' : null
  }

  // Set 550JP — Japanese set
  if (name.includes('550jp')) {
    return hasAny(itemName + sub, SET_550JP_HINTS) ? '550jp' : null
  }

  // 5 buffet tiers — number-based
  const isEligible = ELIGIBLE_PARENT_CATEGORIES.has(parent)
  if (!isEligible) return null

  const isWagyu = hasAny(id + sub, WAGYU_HINTS)
  const isPremiumBeef = hasAny(id + sub, PREMIUM_BEEF_HINTS)
  const isBeef = hasAny(id + sub, BEEF_HINTS)
  const isAlcohol = parent === 'thuc_uong_co_con' ||
    hasAny(id + sub, ALCOHOL_HINTS)

  if (name.includes('1390')) return '1390'
  if (name.includes('1150')) return isWagyu ? null : '1150'
  if (name.includes('680'))  return (isWagyu || isPremiumBeef) ? null : '680'
  if (name.includes('490') || name.includes('380')) {
    if (isWagyu || isBeef || isAlcohol) return null
    return ALLOWED_LOW_TIER_SUBCATS.has(sub) ? '490' : null
  }

  return null
}

/**
 * True iff the item should be FREE when ordered inside the active
 * package. Surcharges and outside-tier items return false.
 */
export function isItemInPackage(
  item: PackageRuleItem,
  packageName: string,
): boolean {
  return getPackageTier(item, packageName) !== null
}

/**
 * Returns a copy of `item` with `price = 0` and `price_display` set
 * when the item is in the package. Otherwise returns the item as-is.
 * Mirrors the customer-side `getModifiedItem()` helper.
 */
export function applyPackage<T extends PackageRuleItem & { price_display?: string }>(
  item: T,
  packageName: string,
): T {
  if (isItemInPackage(item, packageName)) {
    return {
      ...item,
      price: 0,
      price_display: '0K (Trong gói)',
    }
  }
  return item
}

/**
 * Lunch 50% discount: items whose id / name contains "lunch" are
 * half-off.  Applies to BOTH cashier (already done at
 * ReceptionOrderView.vue:1354-1358) and customer (previously MISSING
 * — added when this module was extracted).
 */
export function isLunchItem(item: PackageRuleItem): boolean {
  return hasAny(lc(item.name) + lc(item.id), LUNCH_HINTS)
}

/**
 * Surcharge items ALWAYS show their price even inside a package —
 * this helper centralises that rule so neither side can forget it.
 */
export function isChargeableEvenInPackage(item: PackageRuleItem): boolean {
  return isSurchargeItem(item)
}

/**
 * Net price for ONE line item at the cashier preview level.
 *   1. Free if `isItemInPackage(item, packageName)`
 *      (surcharges always pay full price).
 *   2. Otherwise: half-off if `isLunchItem(item)`.
 *   3. Otherwise: full `item.price`.
 * Multiplied by `quantity` at the end. Math is intentionally cheap
 * (no VAT here — VAT is added by the order-level calculator).
 */
export function calculateItemUnitPrice(
  item: PackageRuleItem,
  packageName: string,
): number {
  const basePrice = Number(item.price ?? 0)
  if (isSurchargeItem(item)) return basePrice
  if (isItemInPackage(item, packageName)) return 0
  if (isLunchItem(item)) return Math.round(basePrice * 0.5)
  return basePrice
}

/**
 * Add VAT + service-charge to a `subtotal` (in VND). Used by both
 * the customer cart preview and the cashier-side order summary so
 * the two screens never disagree on the math.
 *
 * Spec (Ishii 02/07/2026):
 *   service_charge = round(subtotal * 0.05)
 *   vat            = round((subtotal + service_charge) * 0.08)
 *   total          = subtotal + service_charge + vat
 */
export function computeTotals(subtotal: number): {
  subtotal: number
  serviceCharge: number
  vat: number
  total: number
} {
  const sub = Math.max(0, Math.round(Number(subtotal) || 0))
  const serviceCharge = Math.round(sub * 0.05)
  const vat = Math.round((sub + serviceCharge) * 0.08)
  return {
    subtotal: sub,
    serviceCharge,
    vat,
    total: sub + serviceCharge + vat,
  }
}

/**
 * Bulk pricing helper: given a cart `[{id, name, category_id, subCatId?,
 * price, quantity}]` and the active package name, return the subtotal
 * in VND. Lunch discount is applied per-item BEFORE service/VAT.
 */
export function calcCartSubtotal(
  lines: Array<PackageRuleItem & { quantity: number }>,
  packageName: string,
): number {
  return lines.reduce(
    (s, it) => s + calculateItemUnitPrice(it, packageName) * Number(it.quantity ?? 1),
    0,
  )
}

import { ref } from 'vue'
import { supabase } from '@/lib/supabase'

export interface CheckoutResult {
  success: boolean
  bill_id: string
  invoice_id: string
  invoice_number: string
  grand_total: number
  linked_crm_surveys?: number
  subtotal?: number
  discount_total?: number
  voucher_discount?: number
  points_discount?: number
  service_charge_amount?: number
  vat_amount?: number
}

export interface CheckoutTotals {
  subtotal: number
  tier_discount: number
  voucher_discount: number
  points_discount: number
  total_discount: number
  net_before_tax: number
  service_charge_percent: number
  service_charge_amount: number
  vat_rate: number
  vat_amount: number
  grand_total: number
}

export interface CheckoutPreview {
  ok: boolean
  order?: Record<string, unknown>
  table?: Record<string, unknown>
  items?: Array<Record<string, unknown>>
  totals: CheckoutTotals
  voucher_valid: boolean
  error?: string
}

export function useCheckout() {
  const checkoutResult = ref<CheckoutResult | null>(null)
  const loading = ref(false)
  const error = ref<string | null>(null)

  /**
   * Preview the EXACT totals process_checkout will compute. Frontend display
   * matches the eventual bill byte-for-byte — no more 10% UI vs 8% DB drift.
   */
  async function previewCheckout(params: {
    branchId: string
    tableId: string
    orderId?: string
    voucherCode?: string
    pointsToRedeem?: number
    customerId?: string
  }): Promise<CheckoutPreview> {
    loading.value = true
    error.value = null
    try {
      const { data, error: err } = await supabase.rpc('hall_get_checkout_totals', {
        p_branch_id: params.branchId,
        p_table_id: params.tableId,
        p_order_id: params.orderId ?? null,
        p_voucher_code: params.voucherCode ?? null,
        p_points_to_use: params.pointsToRedeem ?? 0,
        p_customer_id: params.customerId ?? null,
      })
      if (err) throw err
      const row = (data ?? {}) as { ok?: boolean; error?: string } & Record<string, unknown>
      return {
        ok: row.ok === true,
        order: row.order as Record<string, unknown> | undefined,
        table: row.table as Record<string, unknown> | undefined,
        items: row.items as Array<Record<string, unknown>> | undefined,
        totals: row.totals as CheckoutTotals,
        voucher_valid: row.voucher_valid === true,
        error: row.error,
      }
    } catch (e: any) {
      error.value = e.message || String(e)
      throw e
    } finally {
      loading.value = false
    }
  }

  /**
   * Single-table summary for floor-plan / table-modal previews.
   * Caches by tableId to avoid re-querying when switching back.
   *
   * IMPORTANT: previously the cache never re-fetched after the first load,
   * which meant opening the same table-modal twice in a row would show
   * stale totals — and if the cashier rapidly opened A then B, the B total
   * would appear to "leak" with the previous A value because both views
   * shared the same Map. We now always force a re-fetch by default and
   * only honour the cache when the caller passes `useCache: true`.
   */
  const _tableCache = new Map<string, CheckoutPreview>()
  async function previewTableSummary(
    branchId: string,
    tableId: string,
    options: { useCache?: boolean } = {},
  ): Promise<CheckoutPreview> {
    if (options.useCache) {
      const cached = _tableCache.get(tableId)
      if (cached) return cached
    }
    const fresh = await previewCheckout({ branchId, tableId })
    _tableCache.set(tableId, fresh)
    return fresh
  }
  /**
   * Drop the cached preview for a table. Pass a tableId to drop just that
   * entry (used by realtime order/table events) or omit to drop everything
   * (used after a successful checkout).
   */
  function clearTableCache(tableId?: string) {
    if (tableId) _tableCache.delete(tableId)
    else _tableCache.clear()
  }

  async function executeCheckout(params: {
    orderId: string
    paymentMethod: string
    paymentRef?: string
    voucherCode?: string
    pointsToRedeem?: number
    serviceChargePct?: number
    vatPct?: number
    branchId: string
    cashierId: string
  }): Promise<CheckoutResult> {
    loading.value = true
    error.value = null
    try {
      const { data, error: err } = await supabase.rpc('process_checkout', {
        p_order_id: params.orderId,
        p_branch_id: params.branchId,
        p_cashier_id: params.cashierId,
        p_payment_method: params.paymentMethod,
        p_voucher_code: params.voucherCode || null,
        p_points_to_use: params.pointsToRedeem || 0,
      })
      if (err) throw err
      checkoutResult.value = data as CheckoutResult
      // After successful checkout, drop the cached preview for this table
      // (the table's bill is now Paid — preview is stale).
      _tableCache.clear()
      return data as CheckoutResult
    } catch (e: any) {
      error.value = e.message || String(e)
      throw e
    } finally {
      loading.value = false
    }
  }

  async function checkout(params: any): Promise<CheckoutResult | null> {
    if (!params?.branchId || !params?.cashierId || !params?.paymentMethod) {
      throw new Error('checkout requires branchId, cashierId and paymentMethod')
    }
    return executeCheckout({
      orderId: params.orderId,
      branchId: params.branchId,
      cashierId: params.cashierId,
      paymentMethod: params.paymentMethod,
      voucherCode: params.voucherCode,
      pointsToRedeem: params.pointsToRedeem,
      paymentRef: params.paymentRef,
      serviceChargePct: params.serviceChargePct,
      vatPct: params.vatPct,
    })
  }

  function printReceipt(result: CheckoutResult): void {
    console.log('Printing receipt for', result.invoice_number)
    window.print()
  }

  return {
    checkoutResult,
    loading,
    error,
    previewCheckout,
    previewTableSummary,
    clearTableCache,
    executeCheckout,
    checkout,
    printReceipt,
  }
}
